//nolint:revive,govet,errcheck
package development

import (
	"testing"

	"github.com/stretchr/testify/require"
)

func TestEnum_RANGING_BEACON_STATUS_FLAG(t *testing.T) {
	t.Run("zero", func(t *testing.T) {
		var e RANGING_BEACON_STATUS_FLAG
		e.UnmarshalText([]byte{})
		e.MarshalText()
		e.String()
	})

	t.Run("first entry", func(t *testing.T) {
		enc, err := RANGING_BEACON_STATUS_FLAG_STATION_SIGNAL_POOR.MarshalText()
		require.NoError(t, err)

		var dec RANGING_BEACON_STATUS_FLAG
		err = dec.UnmarshalText(enc)
		require.NoError(t, err)

		require.Equal(t, RANGING_BEACON_STATUS_FLAG_STATION_SIGNAL_POOR, dec)
	})
}
